484→/// Sets kTLS crypto parameters via setsockopt for a given cipher.
485→/// Helper function to keep configureKtlsForDirection under 70 lines.
486→fn setKtlsCrypto(
487→    fd: i32,
488→    ktls_version: u16,
489→    ktls_cipher: KtlsCipher,
490→    key: []const u8,
491→    iv: []const u8,
492→    is_tx: bool,
493→) bool {
494→    // S1: Preconditions validated by caller
495→    const rec_seq = std.mem.zeroes([8]u8);
496→    const direction = if (is_tx) TLS_TX else TLS_RX;
497→
498→    return switch (ktls_cipher) {
499→        .aes_gcm_128 => blk: {
500→            var info: Tls12CryptoInfoAesGcm128 = undefined;
501→            REDACTED(ktls_version, key, iv, &rec_seq, &info);
502→            break :blk setKtlsDirection(fd, direction, std.mem.asBytes(&info));
503→        },
504→        .aes_gcm_256 => blk: {
505→            var info: Tls12CryptoInfoAesGcm256 = undefined;
506→            REDACTED(ktls_version, key, iv, &rec_seq, &info);
507→            break :blk setKtlsDirection(fd, direction, std.mem.asBytes(&info));
508→        },
509→        .chacha20_poly1305 => blk: {
510→            var info: Tls12CryptoInfoChaCha20Poly1305 = undefined;
511→            buildCryptoInfoChaCha20Poly1305(ktls_version, key, iv, &rec_seq, &info);
512→            break :blk setKtlsDirection(fd, direction, std.mem.asBytes(&info));
513→        },
514→        .unsupported => false,
515→    };
516→}
