530→    assert(@intFromPtr(ssl_ptr) != 0);
531→    assert(ktls_cipher != .unsupported);
532→
533→    // Maximum buffer sizes (ChaCha20: 32-byte key, 12-byte IV)
534→    const max_key_size: usize = 32;
535→    const max_iv_size: usize = 12;
536→    var key_buf: [max_key_size]u8 = undefined;
537→    var iv_buf: [max_iv_size]u8 = undefined;
538→
539→    const key_size: usize = ktls_cipher.keySize();
540→    const iv_total: usize = ktls_cipher.saltSize() + ktls_cipher.ivSize();
541→
542→    // Extract key material for this direction
