561→/// Attempts to enable kernel TLS (kTLS) offload for a connected socket.
562→///
563→/// After a successful TLS handshake, this function extracts the negotiated
564→/// cipher and key material, then configures the kernel to handle TLS
565→/// encryption/decryption for subsequent I/O.
566→///
567→/// Returns:
568→/// - .ktls_enabled: kTLS successfully enabled for both TX and RX
569→/// - .userspace_fallback: kTLS not available, continue using userspace TLS
570→///
571→/// Fallback reasons (all return userspace_fallback, not errors):
572→/// - Non-Linux OS
573→/// - Unsupported TLS version (< TLS 1.2)
574→/// - Unsupported cipher suite
575→/// - Key extraction failure
576→/// - Kernel kTLS module not loaded (ENOPROTOOPT)
577→/// - Kernel cipher not supported (ENOENT)
578→///
579→/// TigerStyle: This function never returns an error for expected fallback cases.
580→/// kTLS is an optimization; failure to enable it is not a connection failure.
581→pub fn tryEnableKtls(
582→    ssl_ptr: *ssl.SSL,
583→    fd: i32,
584→) KtlsResult {
585→    // S1: Preconditions
586→    assert(@intFromPtr(ssl_ptr) != 0); // Valid SSL pointer
587→    assert(fd > 0); // Valid file descriptor
588→
589→    // Step 1: Check runtime kTLS availability (platform + module + env override)
590→    if (!isKtlsRuntimeAvailable()) {
591→        log.debug("kTLS: Runtime unavailable, using userspace fallback", .{});
592→        return .userspace_fallback;
593→    }
594→
595→    // Step 2: Get TLS version - must be TLS 1.2 or 1.3
596→    const tls_version_int: c_int = ssl.SSL_version(ssl_ptr);
597→    if (tls_version_int != ssl.TLS1_2_VERSION and tls_version_int != ssl.TLS1_3_VERSION) {
598→        log.debug("kTLS: Unsupported TLS version 0x{x}", .{tls_version_int});
599→        return .userspace_fallback;
600→    }
601→    const ktls_version: u16 = @intCast(tls_version_int);
602→
603→    // Step 3: Get current cipher
604→    const cipher = ssl.SSL_get_current_cipher(ssl_ptr) orelse {
605→        log.debug("kTLS: No cipher negotiated", .{});
606→        return .userspace_fallback;
607→    };
608→
609→    // Step 4: Map cipher to kTLS cipher type
610→    const cipher_id: u16 = ssl.SSL_CIPHER_get_protocol_id(cipher);
611→    const ktls_cipher = mapCipherToKtls(cipher_id);
