// Main Entry Point
// ============================================================================

/// Attempts to enable kernel TLS (kTLS) offload for a connected socket.
///
/// After a successful TLS handshake, this function extracts the negotiated
/// cipher and key material, then configures the kernel to handle TLS
/// encryption/decryption for subsequent I/O.
///
/// Returns:
/// - .ktls_enabled: kTLS successfully enabled for both TX and RX
/// - .userspace_fallback: kTLS not available, continue using userspace TLS
///
/// Fallback reasons (all return userspace_fallback, not errors):
/// - Non-Linux OS
/// - Unsupported TLS version (< TLS 1.2)
/// - Unsupported cipher suite
/// - Key extraction failure
/// - Kernel kTLS module not loaded (ENOPROTOOPT)
/// - Kernel cipher not supported (ENOENT)
///
/// TigerStyle: This function never returns an error for expected fallback cases.
/// kTLS is an optimization; failure to enable it is not a connection failure.
pub fn tryEnableKtls(
    ssl_ptr: *ssl.SSL,
    fd: i32,
) KtlsResult {
    // S1: Preconditions
    assert(@intFromPtr(ssl_ptr) != 0); // Valid SSL pointer
    assert(fd > 0); // Valid file descriptor

    // Step 1: Check runtime kTLS availability (platform + module + env override)
    if (!isKtlsRuntimeAvailable()) {
        log.debug("kTLS: Runtime unavailable, using userspace fallback", .{});
        return .userspace_fallback;
    }

    // Step 2: Get TLS version - must be TLS 1.2 or 1.3
    const tls_version_int: c_int = ssl.SSL_version(ssl_ptr);
    if (tls_version_int != ssl.TLS1_2_VERSION and tls_version_int != ssl.TLS1_3_VERSION) {
        log.debug("kTLS: Unsupported TLS version 0x{x}", .{tls_version_int});
        return .userspace_fallback;
    }
    const ktls_version: u16 = @intCast(tls_version_int);

    // Step 3: Get current cipher
    const cipher = ssl.SSL_get_current_cipher(ssl_ptr) orelse {
        log.debug("kTLS: No cipher negotiated", .{});
        return .userspace_fallback;
    };

    // Step 4: Map cipher to kTLS cipher type
    const cipher_id: u16 = ssl.SSL_CIPHER_get_protocol_id(cipher);
    const ktls_cipher = mapCipherToKtls(cipher_id);
    if (ktls_cipher == .unsupported) {
        log.debug("kTLS: Cipher 0x{x} not supported by kTLS", .{cipher_id});
        return .userspace_fallback;
    }

    // Step 5: Attach TLS ULP (Upper Layer Protocol) to socket
    if (!attachTlsULP(fd)) {
        log.debug("kTLS: Failed to attach TLS ULP (kernel module not loaded?)", .{});

// ============================================================================
// kTLS Key Extraction Functions
// ============================================================================
// These functions provide access to TLS session keys and random data needed
// for kernel TLS (kTLS) offload. kTLS allows the kernel to encrypt/decrypt
// TLS records directly, bypassing userspace for improved performance.
//
// Key extraction workflow:
// 1. Complete TLS handshake
// 2. Get session via SSL_get_session
// 3. Extract master key, client/server random
// 4. Use SSL_export_keying_material for TLS 1.3+ key derivation
// 5. Pass keys to kernel via setsockopt(SOL_TLS, TLS_TX/TLS_RX)
// ============================================================================

// Session access - required to get master key for kTLS
pub extern fn SSL_get_session(ssl: *const SSL) ?*SSL_SESSION;

// Master key extraction - returns key length written to out buffer
// For TLS 1.2: master secret is 48 bytes
// For TLS 1.3: use SSL_export_keying_material instead
pub extern fn SSL_SESSION_get_master_key(session: *const SSL_SESSION, out: ?[*]u8, max_out: usize) usize;

// Client/server random extraction - needed for TLS 1.2 key derivation
// Both return 32 bytes of random data when complete
pub extern fn SSL_get_client_random(ssl: *const SSL, out: ?[*]u8, max_out: usize) usize;
pub extern fn SSL_get_server_random(ssl: *const SSL, out: ?[*]u8, max_out: usize) usize;

// RFC 5705 key material export - primary method for TLS 1.3 kTLS keys
// Returns 1 on success, 0 on failure
// For kTLS TLS 1.3, use label "EXPORTER-traffic-secret" with appropriate context
pub extern fn SSL_export_keying_material(
    ssl: *SSL,
    out: [*]u8,
    out_len: usize,
    label: [*:0]const u8,
    label_len: usize,
    context: ?[*]const u8,
    context_len: usize,
    use_context: c_int,
) c_int;

// Session resumption
pub extern fn SSL_session_reused(ssl: *const SSL) c_int;

// ALPN helpers
// OpenSSL wire format: concatenated [len][proto-bytes] entries.
// Example for ["h2", "http/1.1"]:
//   0x02 'h' '2' 0x08 'h' 't' 't' 'p' '/' '1' '.' '1'
pub extern fn SSL_CTX_set_alpn_protos(ctx: *SSL_CTX, protos: [*]const u8, protos_len: c_uint) c_int;

