    fn setupKtlsAfterHandshake(ssl_conn: *ssl.SSL, fd: c_int, info: *HandshakeInfo, enable_ktls: bool) Mode {
        if (!enable_ktls) {
            info.ktls_enabled = false;
            return .{ .userspace = ssl_conn };
