    const method = TLS_server_method() orelse return error.NoTlsMethod;
    const ctx = SSL_CTX_new(method) orelse return error.SslCtxNew;
    if (SSL_CTX_set_min_proto_version(ctx, TLS1_2_VERSION) != 1) {
