        const enable_ktls: bool = ktls.isKtlsRuntimeAvailable();
        if (enable_ktls) {
            _ = ssl.SSL_set_options(ssl_conn, ssl.SSL_OP_ENABLE_KTLS);
        }
        ssl.SSL_set_accept_state(ssl_conn);
```

