With:
```zig
fn lockMutex(mutex: *std.atomic.Mutex) error{MutexTimeout}!void {
    assert(@intFromPtr(mutex) != 0);

    var attempts: u32 = 0;
    while (attempts < mutex_lock_max_attempts) : (attempts += 1) {
        if (mutex.tryLock()) {
            consecutive_mutex_timeouts = 0;
            return;
        }
        std.atomic.spinLoopHint();
    }

    consecutive_mutex_timeouts += 1;
    if (consecutive_mutex_timeouts >= max_consecutive_mutex_timeouts) {
        log.err("ReloadableServerCtx: {d} consecutive mutex timeouts — context manager degraded", .{consecutive_mutex_timeouts});
    }
    return error.MutexTimeout;
}
```

