test "native kTLS status reflects runtime availability" {
    ssl.init();
    const ctx = try ssl.createServerCtx();
    defer ssl.SSL_CTX_free(ctx);

    // After creating context, SSL_OP_ENABLE_KTLS should be settable
    const ssl_conn = ssl.SSL_new(ctx) orelse return error.SslNew;
