fn lockMutex(self: *ReloadableServerCtx) error{MutexTimeout}!void {
    assert(@intFromPtr(self) != 0);

    var attempts: u32 = 0;
    while (attempts < mutex_lock_max_attempts) : (attempts += 1) {
        if (self.mutex.tryLock()) {
            self.consecutive_mutex_timeouts = 0;
            return;
        }
        std.atomic.spinLoopHint();
    }

    self.consecutive_mutex_timeouts += 1;
    if (self.consecutive_mutex_timeouts >= max_consecutive_mutex_timeouts) {
        log.err("ReloadableServerCtx: {d} consecutive mutex timeouts — context manager degraded", .{self.consecutive_mutex_timeouts});
    }
    return error.MutexTimeout;
}
```

**Step 3: Propagate in acquire**

