        assert(@intFromPtr(self) != 0);

        lockMutex(&self.mutex);
        defer self.mutex.unlock();
```

With:
```zig
    pub fn acquire(self: *ReloadableServerCtx) Error!Lease {
        assert(@intFromPtr(self) != 0);

        try lockMutex(self);
        defer self.mutex.unlock();
```

